  1	{
  2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
  3	  "title": "EDEN task",
  4	  "description": "A unit of work dispatched to a role. The task object carries kind, state, payload, and optional claim; its state-machine semantics are defined in 04-task-protocol.md.",
  5	  "type": "object",
  6	  "required": ["task_id", "kind", "state", "payload", "created_at", "updated_at"],
  7	  "properties": {
  8	    "task_id": {
  9	      "type": "string",
 10	      "minLength": 1
 11	    },
 12	    "kind": {
 13	      "type": "string",
 14	      "enum": ["plan", "implement", "evaluate"]
 15	    },
 16	    "state": {
 17	      "type": "string",
 18	      "enum": ["pending", "claimed", "submitted", "completed", "failed"]
 19	    },
 20	    "payload": {
 21	      "type": "object"
 22	    },
 23	    "claim": {
 24	      "type": "object",
 25	      "required": ["token", "worker_id", "claimed_at"],
 26	      "properties": {
 27	        "token": {
 28	          "type": "string",
 29	          "minLength": 1
 30	        },
 31	        "worker_id": {
 32	          "type": "string",
 33	          "minLength": 1
 34	        },
 35	        "claimed_at": {
 36	          "type": "string",
 37	          "format": "date-time"
 38	        },
 39	        "expires_at": {
 40	          "type": "string",
 41	          "format": "date-time"
 42	        }
 43	      }
 44	    },
 45	    "created_at": {
 46	      "type": "string",
 47	      "format": "date-time"
 48	    },
 49	    "updated_at": {
 50	      "type": "string",
 51	      "format": "date-time"
 52	    }
 53	  },
 54	  "allOf": [
 55	    {
 56	      "if": {"properties": {"kind": {"const": "plan"}}, "required": ["kind"]},
 57	      "then": {
 58	        "properties": {
 59	          "payload": {
 60	            "type": "object",
 61	            "required": ["experiment_id"],
 62	            "properties": {
 63	              "experiment_id": {"type": "string", "minLength": 1}
 64	            }
 65	          }
 66	        }
 67	      }
 68	    },
 69	    {
 70	      "if": {"properties": {"kind": {"const": "implement"}}, "required": ["kind"]},
 71	      "then": {
 72	        "properties": {
 73	          "payload": {
 74	            "type": "object",
 75	            "required": ["proposal_id"],
 76	            "properties": {
 77	              "proposal_id": {"type": "string", "minLength": 1}
 78	            }
 79	          }
 80	        }
 81	      }
 82	    },
 83	    {
 84	      "if": {"properties": {"kind": {"const": "evaluate"}}, "required": ["kind"]},
 85	      "then": {
 86	        "properties": {
 87	          "payload": {
 88	            "type": "object",
 89	            "required": ["trial_id"],
 90	            "properties": {
 91	              "trial_id": {"type": "string", "minLength": 1}
 92	            }
 93	          }
 94	        }
 95	      }
 96	    },
 97	    {
 98	      "if": {"properties": {"state": {"const": "claimed"}}, "required": ["state"]},
 99	      "then": {"required": ["claim"]}
100	    }
101	  ]
102	}

 1	{
 2	  "$schema": "https://json-schema.org/draft/2020-12/schema",
 3	  "title": "EDEN event envelope",
 4	  "description": "The envelope every event appended to an EDEN event log MUST carry. Type-specific payload shapes under data are enumerated in 05-event-protocol.md.",
 5	  "type": "object",
 6	  "required": ["event_id", "type", "occurred_at", "experiment_id", "data"],
 7	  "properties": {
 8	    "event_id": {
 9	      "type": "string",
10	      "minLength": 1,
11	      "description": "Unique identifier for this event within the log."
12	    },
13	    "type": {
14	      "type": "string",
15	      "pattern": "^[a-z][a-z0-9_]*(\\.[a-z][a-z0-9_]*)+$",
16	      "description": "Dotted type name, e.g. task.claimed, trial.evaluated."
17	    },
18	    "occurred_at": {
19	      "type": "string",
20	      "format": "date-time",
21	      "description": "When the state change happened."
22	    },
23	    "experiment_id": {
24	      "type": "string",
25	      "minLength": 1
26	    },
27	    "data": {
28	      "type": "object",
29	      "description": "Type-specific payload; shape fixed by the event's type registry."
30	    }
31	  }
32	}
